 1	import { type FC, type Ref, useState } from 'react';
 2	
 3	import {
 4	  Flex,
 5	  FlexItem,
 6	  MenuToggle,
 7	  type MenuToggleElement,
 8	  Select as PfSelect,
 9	  SelectList,
10	  SelectOption,
11	} from '@patternfly/react-core';
12	import { BarsIcon } from '@patternfly/react-icons';
13	import { TELEMETRY_EVENTS, TipsTopicSourceComponent } from '@utils/analytics/constants';
14	import { useForkliftAnalytics } from '@utils/analytics/hooks/useForkliftAnalytics';
15	import { useForkliftTranslation } from '@utils/i18n';
16	
17	import type { LearningExperienceTopic } from './types';
18	
19	import './LearningExperiencePanel.scss';
20	
21	type LearningExperienceSelectProps = {
22	  topics: LearningExperienceTopic[];
23	  selectedTopic?: LearningExperienceTopic;
24	  setSelectedTopic: (selectedTopic?: LearningExperienceTopic) => void;
25	};
26	
27	const LearningExperienceSelect: FC<LearningExperienceSelectProps> = ({
28	  selectedTopic,
29	  setSelectedTopic,
30	  topics,
31	}) => {
32	  const { t } = useForkliftTranslation();
33	  const { trackEvent } = useForkliftAnalytics();
34	  const [isSelectOpen, setIsSelectOpen] = useState(false);
35	
36	  const toggle = (toggleRef: Ref<MenuToggleElement>) => {
37	    return (
38	      <MenuToggle
39	        className="pf-v6-u-mt-md"
40	        ref={toggleRef}
41	        onClick={() => {
42	          setIsSelectOpen((prev) => !prev);
43	        }}
44	        isExpanded={isSelectOpen}
45	        style={{ width: '100%' }}
46	      >
47	        <Flex flexWrap={{ default: 'nowrap' }} spacer={{ default: 'spacerSm' }}>
48	          <FlexItem>
49	            <BarsIcon />
50	          </FlexItem>
51	          <FlexItem>{selectedTopic?.title ?? t('Select a topic')}</FlexItem>
52	        </Flex>
53	      </MenuToggle>
54	    );
55	  };
56	
57	  return (
58	    <PfSelect
59	      selected={selectedTopic}
60	      toggle={toggle}
61	      isOpen={isSelectOpen}
62	      onOpenChange={(isOpen) => {
63	        setIsSelectOpen(isOpen);
64	      }}
65	      onSelect={(_ev, value) => {
66	        const newSelection = topics.find((topic) => topic.id === value);
67	        if (newSelection) {
68	          trackEvent(TELEMETRY_EVENTS.TIPS_AND_TRICKS_VISITED, {
69	            componentType: TipsTopicSourceComponent.TipsTopicSelect,
70	            helpTopic: newSelection.trackingEventTopic,
71	          });
72	          setSelectedTopic(newSelection);
73	        }
74	        setIsSelectOpen(false);
75	      }}
76	    >
77	      <SelectList>
78	        {topics.map((topic) => (
79	          <SelectOption value={topic.id} key={topic.id}>
80	            {topic.title}
81	          </SelectOption>
82	        ))}
83	      </SelectList>
84	    </PfSelect>
85	  );
86	};
87	
88	export default LearningExperienceSelect;

